#include <stdio.h>
#include <math.h>

double distance(double x1, double y1, double x2, double y2) {
    return sqrt((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1));
}

double heronsFormula(double a, double b, double c) {
    double s = (a + b + c) / 2.0;
    return sqrt(s * (s - a) * (s - b) * (s - c));
}

int areCollinear(double x1, double y1, double x2, double y2, double x3, double y3) {
    return (x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) == 0;
}

int main(void) {
    double x[4], y[4];
    for (int i = 0; i < 4; i++) scanf("%lf %lf", &x[i], &y[i]);

    // Generate all combinations of 3 points
    for (int i = 0; i < 4; i++) {
        for (int j = i + 1; j < 4; j++) {
            for (int k = j + 1; k < 4; k++) {
                double a = distance(x[i], y[i], x[j], y[j]);
                double b = distance(x[j], y[j], x[k], y[k]);
                double c = distance(x[k], y[k], x[i], y[i]);

                if (areCollinear(x[i], y[i], x[j], y[j], x[k], y[k])) {
                    printf("collinear\n");
                } else {
                    area = heronsFormula(a, b, c);
                    printf("area %.3f\n", area);
                }
            }
        }
    }

    return 0;
}
